{
  "family": "Houben-Hoesch Reaction/Synthesis",
  "candidate": {
    "substrate_smiles": [
      "CC#N",
      "COc1cc(OC)cc(OC)c1"
    ],
    "product_smiles": [
      "CC(=O)c1cc(OC)cc(OC)c1O"
    ],
    "optional_reagent_smiles": [
      "Cl[Zn]Cl",
      "Cl"
    ],
    "rationale": "This is a canonical example of the Houben-Hoesch reaction, featuring the acylation of a highly activated, electron-rich aromatic ring (1,3,5-trimethoxybenzene) with a simple nitrile (acetonitrile). The reaction is catalyzed by a Lewis acid (ZnCl2) and a protic acid (HCl), leading to the formation of an aryl ketone (2,4,6-trimethoxyacetophenone). The reactants and products are simple, acyclic where possible, and clearly illustrate the core transformation of this named reaction.",
    "collision_avoidance_note": "This example uses a highly activated polyalkoxybenzene, which is characteristic of the Houben-Hoesch reaction and distinguishes it from the more general Friedel-Crafts acylation that typically uses less activated arenes. The use of a nitrile as the acylating agent is the key defining feature. Simple, non-fused aromatic rings are used to avoid overlap with reactions involving complex polycyclic aromatic systems."
  }
}
